// Obsługa weryfikacji webhook (GET) i wiadomości (POST)
const req = $input.first().json;

// Facebook wysyła GET z hub.challenge przy weryfikacji
if (req.query && req.query['hub.verify_token']) {
  const VERIFY_TOKEN = $env.FB_VERIFY_TOKEN || 'marcin_bot_2026';
  if (req.query['hub.verify_token'] === VERIFY_TOKEN) {
    return [{ json: { type: 'verification', challenge: req.query['hub.challenge'] } }];
  }
  return [{ json: { type: 'error', message: 'Invalid verify token' } }];
}

// POST - nowa wiadomość
const body = req.body || req;
const entries = body.entry || [];
const messages = [];

for (const entry of entries) {
  const messaging = entry.messaging || [];
  for (const event of messaging) {
    if (event.message && event.message.text) {
      messages.push({
        type: 'message',
        sender_id: event.sender.id,
        recipient_id: event.recipient.id,
        message_text: event.message.text,
        message_id: event.message.mid,
        timestamp: event.timestamp || Date.now()
      });
    }
  }
}

if (messages.length === 0) {
  return [{ json: { type: 'no_message' } }];
}

return messages.map(m => ({ json: m }));

// Wyciągnij odpowiedź Gemini i sprawdź czy wymaga eskalacji
const geminiResponse = $json.candidates?.[0]?.content?.parts?.[0]?.text || 'Przepraszam, wystąpił błąd. Proszę zadzwonić na sekretariat: (81) 825 58 99';
const originalMessage = $('To Wiadomosc?').first().json;

// Sprawdź czy AI nie było w stanie odpowiedzieć (eskalacja do człowieka)
const escalationPhrases = ['nie mam tej informacji', 'nie jestem w stanie', 'proszę zadzwonić', 'nie wiem', 'skontaktować się'];
const needsEscalation = escalationPhrases.some(p => geminiResponse.toLowerCase().includes(p));

// Skróć odpowiedź do limitu Messenger (2000 znaków)
const response = geminiResponse.length > 1900 
  ? geminiResponse.substring(0, 1900) + '...' 
  : geminiResponse;

return [{
  json: {
    sender_id: originalMessage.sender_id,
    message_text: originalMessage.message_text,
    response: response,
    needs_escalation: needsEscalation,
    timestamp: new Date().toISOString()
  }
}];

